class Solution(object):
    def countNoZeroPairs(self, n):
        """
        :type n: int
        :rtype: int
        """
        def has_zero(num):
            return '0' in str(num)

        count = 0
        for a in range(1, n):
            b = n - a
            if not has_zero(a) and not has_zero(b):
                count += 1

        return count
